SELECT FROM ( SELECT , ROWNUM AS RNUM FROM(SELECT FROM (SELECT FROM MST.TB_IP_ASSIGN_MST M LEFT JOIN MST.TB_LVL_MST L ON M.SSVC_LINE_TYPE_CD = L.SSVC_LINE_TYPE_CD AND M.NLVL_MST_SEQ = L.NLVL_MST_SEQ WHERE 1=1
) MM LEFT JOIN MST.TB_SVC_LINE_TYPE_CD LH ON MM.SSVC_LINE_TYPE_CD = LH.SSVC_LINE_TYPE_CD LEFT JOIN MST.TB_LVL_CD LB ON MM.SSVC_GROUP_CD = LB.SLVL_CD LEFT JOIN MST.TB_LVL_CD LO ON MM.SSVC_OBJ_CD = LO.SLVL_CD LEFT JOIN MST.TB_IP_CREATE_TYPE_CD CT ON MM.SIP_CREATE_TYPE_CD = CT.SIP_CREATE_TYPE_CD GROUP BY
ORDER BY MM.SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD, MM.SIP_CREATE_TYPE_CD ) A WHERE ROWNUM <= #{lastIndex} ) A WHERE A.RNUM >= #{firstIndex}

SELECT COUNT(1) totalCount FROM (SELECT FROM (SELECT FROM MST.TB_IP_ASSIGN_MST M LEFT JOIN MST.TB_LVL_MST L ON M.SSVC_LINE_TYPE_CD = L.SSVC_LINE_TYPE_CD AND M.NLVL_MST_SEQ = L.NLVL_MST_SEQ WHERE 1=1
) MM LEFT JOIN MST.TB_SVC_LINE_TYPE_CD LH ON MM.SSVC_LINE_TYPE_CD = LH.SSVC_LINE_TYPE_CD LEFT JOIN MST.TB_LVL_CD LB ON MM.SSVC_GROUP_CD = LB.SLVL_CD LEFT JOIN MST.TB_LVL_CD LO ON MM.SSVC_OBJ_CD = LO.SLVL_CD LEFT JOIN MST.TB_IP_CREATE_TYPE_CD CT ON MM.SIP_CREATE_TYPE_CD = CT.SIP_CREATE_TYPE_CD GROUP BY
) A

