mapper.select:
SELECT FROM ( SELECT
, ROWNUM AS RNUM FROM( SELECT
, MIN(SASSIGN_TYPE_NM) AS SASSIGN_TYPE_NM , ROUND(SUM(NALLOC_CNT),2) AS NALLOC_CNT , ROUND(SUM(NUSE_FREE_CNT),2) AS NUSE_FREE_CNT , ROUND(MST.UF_CONVERT_PERCENT(SUM(NALLOC_CNT) / SUM(NIP_CNT)),2) AS NPERCENT , COUNT(NIP_ASSIGN_MST_SEQ) AS NSUBNET_CNT FROM ( SELECT FROM MST.TB_IP_ASSIGN_MST A WHERE 1=1 AND SASSIGN_LEVEL_CD IN ('IA0003', 'IA0004', 'IA0005', 'IA0006')
) MM LEFT JOIN MST.TB_SVC_LINE_TYPE_CD ILL ON MM.SSVC_LINE_TYPE_CD = ILL.SSVC_LINE_TYPE_CD LEFT JOIN MST.TB_LVL_MST IL ON MM.SSVC_LINE_TYPE_CD = IL.SSVC_LINE_TYPE_CD AND MM.NLVL_MST_SEQ = IL.NLVL_MST_SEQ LEFT JOIN MST.TB_LVL_CD IB ON IL.SSVC_GROUP_CD = IB.SLVL_CD LEFT JOIN MST.TB_LVL_CD IO ON IL.SSVC_OBJ_CD = IO.SLVL_CD LEFT JOIN MST.TB_IP_VERSION_TYPE_CD IV ON MM.SIP_VERSION_TYPE_CD = IV.SIP_VERSION_TYPE_CD LEFT JOIN MST.TB_IP_CREATE_TYPE_CD IT ON MM.SIP_CREATE_TYPE_CD = IT.SIP_CREATE_TYPE_CD LEFT JOIN MST.TB_ASSIGN_TYPE_CD AT ON MM.SASSIGN_TYPE_CD = AT.SASSIGN_TYPE_CD GROUP BY
ORDER BY MM.SSVC_LINE_TYPE_CD , ILL.SSVC_LINE_TYPE_NM , IL.SSVC_GROUP_CD , IB.SLVL_NM , IL.SSVC_OBJ_CD , IO.SLVL_NM , MM.SIP_CREATE_TYPE_CD , SIP_CREATE_TYPE_NM , MM.SIP_VERSION_TYPE_CD , SIP_VERSION_TYPE_NM , PIP_PREFIX ) A WHERE ROWNUM <= #{lastIndex} ) A WHERE A.RNUM >= #{firstIndex}

SELECT COUNT(1) totalCount FROM ( SELECT
, MIN(SASSIGN_TYPE_NM) AS SASSIGN_TYPE_NM , ROUND(SUM(NALLOC_CNT),2) AS NALLOC_CNT , ROUND(SUM(NUSE_FREE_CNT),2) AS NUSE_FREE_CNT , ROUND(MST.UF_CONVERT_PERCENT(SUM(NALLOC_CNT) / SUM(NIP_CNT)),2) AS NPERCENT , COUNT(NIP_ASSIGN_MST_SEQ) AS NSUBNET_CNT FROM ( SELECT FROM MST.TB_IP_ASSIGN_MST A WHERE 1=1 AND SASSIGN_LEVEL_CD IN ('IA0003', 'IA0004', 'IA0005', 'IA0006')
) MM LEFT JOIN MST.TB_SVC_LINE_TYPE_CD ILL ON MM.SSVC_LINE_TYPE_CD = ILL.SSVC_LINE_TYPE_CD LEFT JOIN MST.TB_LVL_MST IL ON MM.SSVC_LINE_TYPE_CD = IL.SSVC_LINE_TYPE_CD AND MM.NLVL_MST_SEQ = IL.NLVL_MST_SEQ LEFT JOIN MST.TB_LVL_CD IB ON IL.SSVC_GROUP_CD = IB.SLVL_CD LEFT JOIN MST.TB_LVL_CD IO ON IL.SSVC_OBJ_CD = IO.SLVL_CD LEFT JOIN MST.TB_IP_VERSION_TYPE_CD IV ON MM.SIP_VERSION_TYPE_CD = IV.SIP_VERSION_TYPE_CD LEFT JOIN MST.TB_IP_CREATE_TYPE_CD IT ON MM.SIP_CREATE_TYPE_CD = IT.SIP_CREATE_TYPE_CD LEFT JOIN MST.TB_ASSIGN_TYPE_CD AT ON MM.SASSIGN_TYPE_CD = AT.SASSIGN_TYPE_CD GROUP BY
) A

SELECT DISTINCT M.SASSIGN_TYPE_CD FROM MST.TB_ASSIGN_TYPE_CD M , MST.TB_IPMS_SVC_MST SM , MST.TB_IPMS_SVC_SUB SS , MST.TB_LVL_MST LV WHERE 1=1 AND M.SASSIGN_TYPE_CD = SM.SASSIGN_TYPE_CD(+) AND SM.NIPMS_SVC_SEQ = SS.NIPMS_SVC_MST_SEQ(+) AND SS.SSVC_LINE_TYPE_CD = LV.SSVC_LINE_TYPE_CD(+)
AND LV.NLVL_MST_SEQ IN
#{item.nlvlSeq}
AND M.SASSIGN_TYPE_CD IN
#{item.sassignTypeCd}
ORDER BY M.SASSIGN_TYPE_CD

WITH T1 AS ( SELECT A.SSVC_LINE_TYPE_CD , A.SSVC_GROUP_CD , A.SSVC_OBJ_CD , A.NLVL_MST_SEQ , A.SASSIGN_TYPE_CD , A.SASSIGN_TYPE_NM , A.NIP_ALL_CNT , A.NIP_MATCH_CNT , A.NIP_UNMATCH_CNT , A.SIP_CREATE_TYPE_CD , A.NIP_ALL_CNT_ALL , A.NIP_MATCH_CNT_ALL , A.NIP_UNMATCH_CNT_ALL , (CASE WHEN NVL(A.NIP_ALL_CNT_ALL,0) = 0 OR NVL(A.NIP_MATCH_CNT_ALL,0) = 0 THEN '0%' ELSE NVL(ROUND(MST.UF_CONVERT_PERCENT(NVL(A.NIP_MATCH_CNT_ALL,0) / NVL(A.NIP_ALL_CNT_ALL,0) ),2),0) || '%' END) AS NIP_MATCH_PER_ALL FROM ( SELECT C.SSVC_LINE_TYPE_CD , C.SSVC_GROUP_CD , C.SSVC_OBJ_CD , C.NLVL_MST_SEQ , A.SASSIGN_TYPE_CD , A.SASSIGN_TYPE_NM , NVL(B.SIP_CREATE_TYPE_CD, #{sipCreateTypeCd, jdbcType=CHAR}) AS SIP_CREATE_TYPE_CD , B.NIP_ALL_CNT , B.NIP_MATCH_CNT , B.NIP_UNMATCH_CNT , SUM(NVL(B.NIP_ALL_CNT,0)) OVER(PARTITION BY C.SSVC_LINE_TYPE_CD, C.SSVC_GROUP_CD, C.SSVC_OBJ_CD, C.NLVL_MST_SEQ) AS NIP_ALL_CNT_ALL , SUM(NVL(B.NIP_MATCH_CNT,0)) OVER(PARTITION BY C.SSVC_LINE_TYPE_CD, C.SSVC_GROUP_CD, C.SSVC_OBJ_CD, C.NLVL_MST_SEQ) AS NIP_MATCH_CNT_ALL , SUM(NVL(B.NIP_UNMATCH_CNT,0)) OVER(PARTITION BY C.SSVC_LINE_TYPE_CD, C.SSVC_GROUP_CD, C.SSVC_OBJ_CD, C.NLVL_MST_SEQ) AS NIP_UNMATCH_CNT_ALL FROM ( SELECT DISTINCT M.SASSIGN_TYPE_CD , M.SASSIGN_TYPE_NM , LV.SSVC_LINE_TYPE_CD , LV.NLVL_MST_SEQ , LV.SSVC_GROUP_CD , LV.SSVC_OBJ_CD FROM MST.TB_ASSIGN_TYPE_CD M , MST.TB_IPMS_SVC_MST SM , MST.TB_IPMS_SVC_SUB SS , MST.TB_LVL_MST LV WHERE 1=1 AND M.SASSIGN_TYPE_CD = SM.SASSIGN_TYPE_CD(+) AND SM.NIPMS_SVC_SEQ = SS.NIPMS_SVC_MST_SEQ(+) AND SS.SSVC_LINE_TYPE_CD = LV.SSVC_LINE_TYPE_CD(+) UNION SELECT 'SA0000' as SASSIGN_TYPE_CD , '----------' as SASSIGN_TYPE_NM , A.SSVC_LINE_TYPE_CD , A.NLVL_MST_SEQ , B.SSVC_GROUP_CD , B.SSVC_OBJ_CD FROM MST.TB_INTGRM_ROUTING_STATS_MST A, MST.TB_LVL_MST B WHERE 1=1 AND B.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND A.SASSIGN_TYPE_CD = 'SA0000' GROUP BY A.SSVC_LINE_TYPE_CD , A.NLVL_MST_SEQ, B.SSVC_GROUP_CD , B.SSVC_OBJ_CD ) A , ( SELECT SCOLLECT_DT , SSVC_LINE_TYPE_CD , NLVL_MST_SEQ , SIP_CREATE_TYPE_CD , SASSIGN_TYPE_CD , NIP_ALL_CNT , NIP_MATCH_CNT , NIP_UNMATCH_CNT FROM MST.TB_INTGRM_ROUTING_STATS_MST WHERE 1=1
AND SCOLLECT_DT = #{searchBgnDe, jdbcType=VARCHAR}
AND (SCOLLECT_DT) IN ( SELECT MAX(SCOLLECT_DT) FROM MST.TB_INTGRM_ROUTING_STATS_MST WHERE 1=1 )
AND SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR}
) B , MST.TB_LVL_MST C WHERE 1=1 AND B.SSVC_LINE_TYPE_CD(+) = A.SSVC_LINE_TYPE_CD AND B.NLVL_MST_SEQ(+) = A.NLVL_MST_SEQ AND B.SASSIGN_TYPE_CD(+) = A.SASSIGN_TYPE_CD AND C.SSVC_LINE_TYPE_CD(+) = A.SSVC_LINE_TYPE_CD AND C.SSVC_GROUP_CD(+) = A.SSVC_GROUP_CD AND C.SSVC_OBJ_CD(+) = A.SSVC_OBJ_CD AND C.SSVC_LINE_TYPE_CD IN ('CL0001', 'CL0002', 'CL0003')
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND A.NLVL_MST_SEQ IN
#{item.nlvlSeq}
ORDER BY A.SASSIGN_TYPE_CD ) A ) SELECT A.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD , A.SSVC_OBJ_NM , A.SIP_CREATE_TYPE_NM , A.NIP_ALL_CNT_ALL , A.NIP_MATCH_CNT_ALL , A.NIP_UNMATCH_CNT_ALL , A.NIP_MATCH_PER_ALL
, NVL(TO_CHAR(MIN(CASE A.SASSIGN_TYPE_CD WHEN #{item.code} THEN A.NIP_ALL_CNT END)),'0') AS NIP_ALL_CNT_${item.code} , NVL(TO_CHAR(MIN(CASE A.SASSIGN_TYPE_CD WHEN #{item.code} THEN A.NIP_MATCH_CNT END)), '0') AS NIP_MATCH_CNT_${item.code} , NVL(TO_CHAR(MIN(CASE A.SASSIGN_TYPE_CD WHEN #{item.code} THEN A.NIP_UNMATCH_CNT END)), '0') AS NIP_UNMATCH_CNT_${item.code} , (CASE WHEN NVL(TO_CHAR(MIN(CASE A.SASSIGN_TYPE_CD WHEN #{item.code} THEN A.NIP_ALL_CNT END)), '0') = '0' OR NVL(TO_CHAR(MIN(CASE A.SASSIGN_TYPE_CD WHEN #{item.code} THEN A.NIP_MATCH_CNT END)), '0') = '0' THEN '0%' ELSE NVL(ROUND(MST.UF_CONVERT_PERCENT(NVL(MIN(CASE A.SASSIGN_TYPE_CD WHEN #{item.code} THEN A.NIP_MATCH_CNT END),0) / NVL(MIN(CASE A.SASSIGN_TYPE_CD WHEN #{item.code} THEN A.NIP_ALL_CNT END),0) ),2),0) || '%' END) AS NIP_MATCH_PER_${item.code}
FROM ( SELECT T1.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , T1.SSVC_GROUP_CD , T1.SSVC_OBJ_CD , C.SLVL_NM AS SSVC_GROUP_NM , T1.NLVL_MST_SEQ , D.SLVL_NM AS SSVC_OBJ_NM , T1.SASSIGN_TYPE_CD , T1.SASSIGN_TYPE_NM , E.SIP_CREATE_TYPE_NM , T1.NIP_ALL_CNT , T1.NIP_MATCH_CNT , T1.NIP_UNMATCH_CNT , T1.NIP_ALL_CNT_ALL , T1.NIP_MATCH_CNT_ALL , T1.NIP_UNMATCH_CNT_ALL , T1.NIP_MATCH_PER_ALL FROM T1 , MST.TB_SVC_LINE_TYPE_CD A , MST.TB_LVL_MST B , MST.TB_LVL_CD C , MST.TB_LVL_CD D , MST.TB_IP_CREATE_TYPE_CD E WHERE 1=1 AND A.SSVC_LINE_TYPE_CD(+) = T1.SSVC_LINE_TYPE_CD AND B.NLVL_MST_SEQ = T1.NLVL_MST_SEQ AND C.SLVL_CD(+) = B.SSVC_GROUP_CD AND D.SLVL_CD(+) = B.SSVC_OBJ_CD AND E.SIP_CREATE_TYPE_CD(+) = T1.SIP_CREATE_TYPE_CD
AND T1.SASSIGN_TYPE_CD IN
#{item.code}
AND T1.SASSIGN_TYPE_CD IN
#{item}
) A GROUP BY A.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD , A.SSVC_OBJ_NM , A.SIP_CREATE_TYPE_NM , A.NIP_ALL_CNT_ALL , A.NIP_MATCH_CNT_ALL , A.NIP_UNMATCH_CNT_ALL , A.NIP_MATCH_PER_ALL ORDER BY A.SSVC_LINE_TYPE_CD , A.SSVC_GROUP_CD , A.SSVC_OBJ_CD

WITH T1 AS ( SELECT A.SSVC_LINE_TYPE_CD , A.SSVC_GROUP_CD , A.SSVC_OBJ_CD , A.NLVL_MST_SEQ , A.SASSIGN_TYPE_CD , A.SASSIGN_TYPE_NM , A.SIP_CREATE_TYPE_CD , A.SIP_VERSION_TYPE_CD , SUM(A.NALL_CNT) AS NALL_CNT , SUM(A.NALLOC_CNT) AS NALLOC_CNT , SUM(A.NASSIGN_CNT) AS NASSIGN_CNT , A.NALL_CNT_ALL , A.NALLOC_CNT_ALL , A.NASSIGN_CNT_ALL FROM ( SELECT C.SSVC_LINE_TYPE_CD , C.SSVC_GROUP_CD , C.SSVC_OBJ_CD , C.NLVL_MST_SEQ , A.SASSIGN_TYPE_CD , A.SASSIGN_TYPE_NM , NVL(B.SIP_CREATE_TYPE_CD, #{sipCreateTypeCd, jdbcType=CHAR}) AS SIP_CREATE_TYPE_CD , NVL(B.SIP_VERSION_TYPE_CD, #{sipVersionTypeCd, jdbcType=CHAR}) AS SIP_VERSION_TYPE_CD , NVL(B.NALL_CNT,0) AS NALL_CNT , NVL(B.NALLOC_CNT,0) AS NALLOC_CNT , NVL(B.NASSIGN_CNT,0) AS NASSIGN_CNT , SUM(NVL(B.NALL_CNT,0)) OVER(PARTITION BY C.SSVC_LINE_TYPE_CD, C.SSVC_GROUP_CD, C.SSVC_OBJ_CD, C.NLVL_MST_SEQ) AS NALL_CNT_ALL , SUM(NVL(B.NALLOC_CNT,0)) OVER(PARTITION BY C.SSVC_LINE_TYPE_CD, C.SSVC_GROUP_CD, C.SSVC_OBJ_CD, C.NLVL_MST_SEQ) AS NALLOC_CNT_ALL , SUM(NVL(B.NASSIGN_CNT,0)) OVER(PARTITION BY C.SSVC_LINE_TYPE_CD, C.SSVC_GROUP_CD, C.SSVC_OBJ_CD, C.NLVL_MST_SEQ) AS NASSIGN_CNT_ALL FROM ( SELECT A.SSVC_LINE_TYPE_CD , C.SSVC_GROUP_CD , C.SSVC_OBJ_CD , C.NLVL_MST_SEQ , B.SASSIGN_TYPE_CD , B.SASSIGN_TYPE_NM FROM MST.TB_SVC_LINE_TYPE_CD A , ( SELECT M.SASSIGN_TYPE_CD , M.SASSIGN_TYPE_NM FROM MST.TB_ASSIGN_TYPE_CD M , MST.TB_IPMS_SVC_MST SM , MST.TB_IPMS_SVC_SUB SS , MST.TB_LVL_MST LV WHERE 1=1 AND M.SASSIGN_TYPE_CD = SM.SASSIGN_TYPE_CD(+) AND SM.NIPMS_SVC_SEQ = SS.NIPMS_SVC_MST_SEQ(+) AND SS.SSVC_LINE_TYPE_CD = LV.SSVC_LINE_TYPE_CD(+) GROUP BY M.SASSIGN_TYPE_CD , M.SASSIGN_TYPE_NM ) B , MST.TB_LVL_MST C WHERE 1=1 AND C.SSVC_LINE_TYPE_CD(+) = A.SSVC_LINE_TYPE_CD ) A , ( SELECT SHIST_DT , SSVC_LINE_TYPE_CD , NLVL_MST_SEQ , SASSIGN_TYPE_CD , SIP_CREATE_TYPE_CD , SIP_VERSION_TYPE_CD , NALL_CNT , NALLOC_CNT , NASSIGN_CNT FROM MST.TB_ORG_SVC_STATS_MST WHERE 1=1 AND SHIST_DT = #{searchBgnDe, jdbcType=VARCHAR}
AND SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND SIP_VERSION_TYPE_CD = #{sipVersionTypeCd, jdbcType=CHAR}
AND SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR}
) B , MST.TB_LVL_MST C WHERE 1=1 AND B.SSVC_LINE_TYPE_CD(+) = A.SSVC_LINE_TYPE_CD AND B.NLVL_MST_SEQ(+) = A.NLVL_MST_SEQ AND B.SASSIGN_TYPE_CD(+) = A.SASSIGN_TYPE_CD AND C.SSVC_LINE_TYPE_CD(+) = A.SSVC_LINE_TYPE_CD AND C.SSVC_GROUP_CD(+) = A.SSVC_GROUP_CD AND C.SSVC_OBJ_CD(+) = A.SSVC_OBJ_CD
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND C.NLVL_MST_SEQ IN
#{item.nlvlSeq}
ORDER BY A.SASSIGN_TYPE_CD ) A GROUP BY A.SSVC_LINE_TYPE_CD , A.SSVC_GROUP_CD , A.SSVC_OBJ_CD , A.NLVL_MST_SEQ , A.SASSIGN_TYPE_CD , A.SASSIGN_TYPE_NM , A.SIP_CREATE_TYPE_CD , A.SIP_VERSION_TYPE_CD , A.NALL_CNT_ALL , A.NALLOC_CNT_ALL , A.NASSIGN_CNT_ALL ) SELECT CASE WHEN GROUPING(t.SSVC_LINE_TYPE_CD) = 1 THEN '소계' ELSE MAX(t.SSVC_LINE_TYPE_CD) END AS SSVC_LINE_TYPE_CD , CASE WHEN GROUPING(t.SSVC_LINE_TYPE_CD) = 1 THEN '소계' ELSE MAX(t.SSVC_LINE_TYPE_NM) END AS SSVC_LINE_TYPE_NM , CASE WHEN GROUPING(t.SSVC_GROUP_CD) = 1 THEN '소계' ELSE MAX(t.SSVC_GROUP_CD) END AS SSVC_GROUP_CD , CASE WHEN GROUPING(t.SSVC_GROUP_CD) = 1 THEN '소계' ELSE MAX(t.SSVC_GROUP_NM) END AS SSVC_GROUP_NM , CASE WHEN GROUPING(t.SSVC_OBJ_CD) = 1 THEN '소계' ELSE MAX(t.SSVC_OBJ_CD) END AS SSVC_OBJ_CD , CASE WHEN GROUPING(t.SSVC_OBJ_CD) = 1 THEN '소계' ELSE MAX(t.SSVC_OBJ_NM) END AS SSVC_OBJ_NM , MAX(t.SIP_CREATE_TYPE_NM) AS SIP_CREATE_TYPE_NM , MAX(t.SIP_VERSION_TYPE_NM) AS SIP_CREATE_TYPE_NM , SUM(t.NALL_CNT_ALL) AS NALL_CNT_ALL , SUM(t.NALLOC_CNT_ALL) AS NALLOC_CNT_ALL , SUM(t.NASSIGN_CNT_ALL) AS NASSIGN_CNT_ALL , CASE WHEN SUM(t.NALL_CNT_ALL) = 0 then 0 else ROUND((SUM(t.NALLOC_CNT_ALL)/SUM(t.NALL_CNT_ALL)*100),2) end as NALL_CNT_ALL_RATE
, SUM(NALL_CNT_${item.code}) AS NALL_CNT_${item.code} , SUM(NALLOC_CNT_${item.code}) AS NALLOC_CNT_${item.code} , SUM(NASSIGN_CNT_${item.code}) AS NASSIGN_CNT_${item.code} , CASE WHEN SUM(t.NALL_CNT_${item.code}) = 0 then 0 else ROUND((SUM(t.NALLOC_CNT_${item.code})/SUM(t.NALL_CNT_${item.code})*100),2) end as NALL_CNT_${item.code}_RATE
FROM ( SELECT A.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD , A.SSVC_OBJ_NM , A.SIP_CREATE_TYPE_NM , A.SIP_VERSION_TYPE_NM , A.NALL_CNT_ALL , A.NALLOC_CNT_ALL , A.NASSIGN_CNT_ALL
, NVL(TO_CHAR(MIN(CASE A.SASSIGN_TYPE_CD WHEN #{item.code} THEN A.NALL_CNT END)),'0') AS NALL_CNT_${item.code} , NVL(TO_CHAR(MIN(CASE A.SASSIGN_TYPE_CD WHEN #{item.code} THEN A.NALLOC_CNT END)), '0') AS NALLOC_CNT_${item.code} , NVL(TO_CHAR(MIN(CASE A.SASSIGN_TYPE_CD WHEN #{item.code} THEN A.NASSIGN_CNT END)), '0') AS NASSIGN_CNT_${item.code}
FROM ( SELECT T1.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , T1.SSVC_GROUP_CD , T1.SSVC_OBJ_CD , C.SLVL_NM AS SSVC_GROUP_NM , T1.NLVL_MST_SEQ , D.SLVL_NM AS SSVC_OBJ_NM , T1.SASSIGN_TYPE_CD , T1.SASSIGN_TYPE_NM , E.SIP_CREATE_TYPE_NM , F.SIP_VERSION_TYPE_NM , T1.NALL_CNT , T1.NALLOC_CNT , T1.NASSIGN_CNT , T1.NALL_CNT_ALL , T1.NALLOC_CNT_ALL , T1.NASSIGN_CNT_ALL FROM T1 , MST.TB_SVC_LINE_TYPE_CD A , MST.TB_LVL_MST B , MST.TB_LVL_CD C , MST.TB_LVL_CD D , MST.TB_IP_CREATE_TYPE_CD E , MST.TB_IP_VERSION_TYPE_CD F WHERE 1=1 AND A.SSVC_LINE_TYPE_CD(+) = T1.SSVC_LINE_TYPE_CD AND B.NLVL_MST_SEQ = T1.NLVL_MST_SEQ AND C.SLVL_CD(+) = B.SSVC_GROUP_CD AND D.SLVL_CD(+) = B.SSVC_OBJ_CD AND E.SIP_CREATE_TYPE_CD(+) = T1.SIP_CREATE_TYPE_CD AND F.SIP_VERSION_TYPE_CD(+) = T1.SIP_VERSION_TYPE_CD
AND T1.SASSIGN_TYPE_CD IN
#{item.code}
AND T1.SASSIGN_TYPE_CD IN
#{item}
) A GROUP BY A.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD , A.SSVC_OBJ_NM , A.SIP_CREATE_TYPE_NM , A.SIP_VERSION_TYPE_NM , A.NALL_CNT_ALL , A.NALLOC_CNT_ALL , A.NASSIGN_CNT_ALL ORDER BY A.SSVC_LINE_TYPE_CD , A.SSVC_GROUP_CD , A.SSVC_OBJ_CD ) t GROUP BY ROLLUP( t.SSVC_LINE_TYPE_CD , t.SSVC_GROUP_CD , t.SSVC_OBJ_CD )

WITH T1 AS ( SELECT A.SSVC_LINE_TYPE_CD , A.SASSIGN_TYPE_CD , A.SASSIGN_TYPE_NM , A.SIP_CREATE_TYPE_CD , A.SIP_VERSION_TYPE_CD , A.NALL_CNT , A.NALLOC_CNT , A.NASSIGN_CNT , A.NALL_CNT_ALL , A.NALLOC_CNT_ALL , A.NASSIGN_CNT_ALL FROM ( SELECT C.SSVC_LINE_TYPE_CD , A.SASSIGN_TYPE_CD , A.SASSIGN_TYPE_NM , NVL(B.SIP_CREATE_TYPE_CD, #{sipCreateTypeCd, jdbcType=CHAR}) AS SIP_CREATE_TYPE_CD , NVL(B.SIP_VERSION_TYPE_CD, #{sipVersionTypeCd, jdbcType=CHAR}) AS SIP_VERSION_TYPE_CD , NVL(B.NALL_CNT,0) AS NALL_CNT , NVL(B.NALLOC_CNT,0) AS NALLOC_CNT , NVL(B.NASSIGN_CNT,0) AS NASSIGN_CNT , SUM(NVL(B.NALL_CNT,0)) OVER(PARTITION BY A.SSVC_LINE_TYPE_CD, A.SASSIGN_TYPE_CD) AS NALL_CNT_ALL , SUM(NVL(B.NALLOC_CNT,0)) OVER(PARTITION BY A.SSVC_LINE_TYPE_CD, A.SASSIGN_TYPE_CD) AS NALLOC_CNT_ALL , SUM(NVL(B.NASSIGN_CNT,0)) OVER(PARTITION BY A.SSVC_LINE_TYPE_CD, A.SASSIGN_TYPE_CD) AS NASSIGN_CNT_ALL FROM ( SELECT A.SSVC_LINE_TYPE_CD , C.SSVC_GROUP_CD , C.SSVC_OBJ_CD , C.NLVL_MST_SEQ , B.SASSIGN_TYPE_CD , B.SASSIGN_TYPE_NM FROM MST.TB_SVC_LINE_TYPE_CD A , ( SELECT M.SASSIGN_TYPE_CD , M.SASSIGN_TYPE_NM FROM MST.TB_ASSIGN_TYPE_CD M , MST.TB_IPMS_SVC_MST SM , MST.TB_IPMS_SVC_SUB SS , MST.TB_LVL_MST LV WHERE 1=1 AND M.SASSIGN_TYPE_CD = SM.SASSIGN_TYPE_CD(+) AND SM.NIPMS_SVC_SEQ = SS.NIPMS_SVC_MST_SEQ(+) AND SS.SSVC_LINE_TYPE_CD = LV.SSVC_LINE_TYPE_CD(+) GROUP BY M.SASSIGN_TYPE_CD , M.SASSIGN_TYPE_NM ) B , MST.TB_LVL_MST C WHERE 1=1 AND C.SSVC_LINE_TYPE_CD(+) = A.SSVC_LINE_TYPE_CD ) A , ( SELECT SHIST_DT , SSVC_LINE_TYPE_CD , NLVL_MST_SEQ , SASSIGN_TYPE_CD , SIP_CREATE_TYPE_CD , SIP_VERSION_TYPE_CD , NALL_CNT , NALLOC_CNT , NASSIGN_CNT FROM MST.TB_ORG_SVC_STATS_MST WHERE 1=1 AND SHIST_DT = #{searchBgnDe, jdbcType=VARCHAR}
AND SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND SIP_VERSION_TYPE_CD = #{sipVersionTypeCd, jdbcType=CHAR}
AND SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR}
) B , MST.TB_LVL_MST C WHERE 1=1 AND B.SSVC_LINE_TYPE_CD(+) = A.SSVC_LINE_TYPE_CD AND B.NLVL_MST_SEQ(+) = A.NLVL_MST_SEQ AND B.SASSIGN_TYPE_CD(+) = A.SASSIGN_TYPE_CD AND C.SSVC_LINE_TYPE_CD(+) = A.SSVC_LINE_TYPE_CD AND C.SSVC_GROUP_CD(+) = A.SSVC_GROUP_CD AND C.SSVC_OBJ_CD(+) = A.SSVC_OBJ_CD
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND C.NLVL_MST_SEQ IN
#{item.nlvlSeq}
ORDER BY A.SASSIGN_TYPE_CD ) A ) SELECT A.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , A.SASSIGN_TYPE_CD , A.SASSIGN_TYPE_NM , A.SIP_CREATE_TYPE_NM , A.SIP_VERSION_TYPE_NM , A.NALL_CNT_ALL , A.NALLOC_CNT_ALL , A.NASSIGN_CNT_ALL
, NVL(TO_CHAR(MIN(CASE A.SSVC_LINE_TYPE_CD WHEN #{item.code} THEN A.NALL_CNT END)),'0') AS NALL_CNT_${item.code} , NVL(TO_CHAR(MIN(CASE A.SSVC_LINE_TYPE_CD WHEN #{item.code} THEN A.NALLOC_CNT END)), '0') AS NALLOC_CNT_${item.code} , NVL(TO_CHAR(MIN(CASE A.SSVC_LINE_TYPE_CD WHEN #{item.code} THEN A.NASSIGN_CNT END)), '0') AS NASSIGN_CNT_${item.code}
FROM ( SELECT T1.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , T1.SASSIGN_TYPE_CD , T1.SASSIGN_TYPE_NM , E.SIP_CREATE_TYPE_NM , F.SIP_VERSION_TYPE_NM , T1.NALL_CNT , T1.NALLOC_CNT , T1.NASSIGN_CNT , T1.NALL_CNT_ALL , T1.NALLOC_CNT_ALL , T1.NASSIGN_CNT_ALL FROM T1 , MST.TB_SVC_LINE_TYPE_CD A , MST.TB_IP_CREATE_TYPE_CD E , MST.TB_IP_VERSION_TYPE_CD F WHERE 1=1 AND A.SSVC_LINE_TYPE_CD(+) = T1.SSVC_LINE_TYPE_CD AND E.SIP_CREATE_TYPE_CD(+) = T1.SIP_CREATE_TYPE_CD AND F.SIP_VERSION_TYPE_CD(+) = T1.SIP_VERSION_TYPE_CD
AND T1.SSVC_LINE_TYPE_CD IN
#{item.code}
AND T1.SSVC_LINE_TYPE_CD IN
#{item}
) A GROUP BY A.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , A.SASSIGN_TYPE_CD , A.SASSIGN_TYPE_NM , A.SIP_CREATE_TYPE_NM , A.SIP_VERSION_TYPE_NM , A.NALL_CNT_ALL , A.NALLOC_CNT_ALL , A.NASSIGN_CNT_ALL ORDER BY A.SSVC_LINE_TYPE_CD , A.SASSIGN_TYPE_CD

WITH T1 AS ( SELECT A.SSVC_LINE_TYPE_CD , A.SASSIGN_TYPE_CD , A.SASSIGN_TYPE_NM , A.SIP_CREATE_TYPE_CD , A.SIP_VERSION_TYPE_CD , SUM(A.NALL_CNT) AS NALL_CNT , SUM(A.NALLOC_CNT) AS NALLOC_CNT , SUM(A.NASSIGN_CNT) AS NASSIGN_CNT , A.NALL_CNT_ALL , A.NALLOC_CNT_ALL , A.NASSIGN_CNT_ALL FROM ( SELECT A.SSVC_LINE_TYPE_CD , A.SASSIGN_TYPE_CD , A.SASSIGN_TYPE_NM , NVL(B.SIP_CREATE_TYPE_CD, #{sipCreateTypeCd, jdbcType=CHAR}) AS SIP_CREATE_TYPE_CD , NVL(B.SIP_VERSION_TYPE_CD, #{sipVersionTypeCd, jdbcType=CHAR}) AS SIP_VERSION_TYPE_CD , NVL(B.NALL_CNT,0) AS NALL_CNT , NVL(B.NALLOC_CNT,0) AS NALLOC_CNT , NVL(B.NASSIGN_CNT,0) AS NASSIGN_CNT , SUM(NVL(B.NALL_CNT,0)) OVER(PARTITION BY A.SASSIGN_TYPE_CD) AS NALL_CNT_ALL , SUM(NVL(B.NALLOC_CNT,0)) OVER(PARTITION BY A.SASSIGN_TYPE_CD) AS NALLOC_CNT_ALL , SUM(NVL(B.NASSIGN_CNT,0)) OVER(PARTITION BY A.SASSIGN_TYPE_CD) AS NASSIGN_CNT_ALL FROM ( SELECT A.SSVC_LINE_TYPE_CD , C.SSVC_GROUP_CD , C.SSVC_OBJ_CD , C.NLVL_MST_SEQ , B.SASSIGN_TYPE_CD , B.SASSIGN_TYPE_NM FROM MST.TB_SVC_LINE_TYPE_CD A , ( SELECT M.SASSIGN_TYPE_CD , M.SASSIGN_TYPE_NM FROM MST.TB_ASSIGN_TYPE_CD M , MST.TB_IPMS_SVC_MST SM , MST.TB_IPMS_SVC_SUB SS , MST.TB_LVL_MST LV WHERE 1=1 AND M.SASSIGN_TYPE_CD = SM.SASSIGN_TYPE_CD(+) AND SM.NIPMS_SVC_SEQ = SS.NIPMS_SVC_MST_SEQ(+) AND SS.SSVC_LINE_TYPE_CD = LV.SSVC_LINE_TYPE_CD(+) GROUP BY M.SASSIGN_TYPE_CD , M.SASSIGN_TYPE_NM ) B , MST.TB_LVL_MST C WHERE 1=1 AND C.SSVC_LINE_TYPE_CD(+) = A.SSVC_LINE_TYPE_CD ) A , ( SELECT SHIST_DT , SSVC_LINE_TYPE_CD , NLVL_MST_SEQ , SASSIGN_TYPE_CD , SIP_CREATE_TYPE_CD , SIP_VERSION_TYPE_CD , NALL_CNT , NALLOC_CNT , NASSIGN_CNT FROM MST.TB_ORG_SVC_STATS_MST WHERE 1=1 AND SHIST_DT = #{searchBgnDe, jdbcType=VARCHAR}
AND SIP_VERSION_TYPE_CD = #{sipVersionTypeCd, jdbcType=CHAR}
AND SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR}
) B WHERE 1=1 AND B.SSVC_LINE_TYPE_CD(+) = A.SSVC_LINE_TYPE_CD AND B.NLVL_MST_SEQ(+) = A.NLVL_MST_SEQ AND B.SASSIGN_TYPE_CD(+) = A.SASSIGN_TYPE_CD ORDER BY A.SASSIGN_TYPE_CD ) A GROUP BY A.SSVC_LINE_TYPE_CD , A.SASSIGN_TYPE_CD , A.SASSIGN_TYPE_NM , A.SIP_CREATE_TYPE_CD , A.SIP_VERSION_TYPE_CD , A.NALL_CNT_ALL , A.NALLOC_CNT_ALL , A.NASSIGN_CNT_ALL ) SELECT A.SASSIGN_TYPE_CD , A.SASSIGN_TYPE_NM , A.SIP_CREATE_TYPE_NM , A.SIP_VERSION_TYPE_NM , A.NALL_CNT_ALL , A.NALLOC_CNT_ALL , A.NASSIGN_CNT_ALL
, NVL(TO_CHAR(MIN(CASE A.SSVC_LINE_TYPE_CD WHEN #{item.code} THEN A.NALL_CNT END)),'0') AS NALL_CNT_${item.code} , NVL(TO_CHAR(MIN(CASE A.SSVC_LINE_TYPE_CD WHEN #{item.code} THEN A.NALLOC_CNT END)), '0') AS NALLOC_CNT_${item.code} , NVL(TO_CHAR(MIN(CASE A.SSVC_LINE_TYPE_CD WHEN #{item.code} THEN A.NASSIGN_CNT END)), '0') AS NASSIGN_CNT_${item.code}
FROM ( SELECT T1.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , T1.SASSIGN_TYPE_CD , T1.SASSIGN_TYPE_NM , E.SIP_CREATE_TYPE_NM , F.SIP_VERSION_TYPE_NM , T1.NALL_CNT , T1.NALLOC_CNT , T1.NASSIGN_CNT , T1.NALL_CNT_ALL , T1.NALLOC_CNT_ALL , T1.NASSIGN_CNT_ALL FROM T1 , MST.TB_SVC_LINE_TYPE_CD A , MST.TB_IP_CREATE_TYPE_CD E , MST.TB_IP_VERSION_TYPE_CD F WHERE 1=1 AND A.SSVC_LINE_TYPE_CD(+) = T1.SSVC_LINE_TYPE_CD AND E.SIP_CREATE_TYPE_CD(+) = T1.SIP_CREATE_TYPE_CD AND F.SIP_VERSION_TYPE_CD(+) = T1.SIP_VERSION_TYPE_CD
AND T1.SSVC_LINE_TYPE_CD IN
#{item.code}
) A GROUP BY A.SASSIGN_TYPE_CD , A.SASSIGN_TYPE_NM , A.SIP_CREATE_TYPE_NM , A.SIP_VERSION_TYPE_NM , A.NALL_CNT_ALL , A.NALLOC_CNT_ALL , A.NASSIGN_CNT_ALL ORDER BY A.SASSIGN_TYPE_CD

WITH T1 AS ( SELECT A.SSVC_LINE_TYPE_NM , A.SSVC_LINE_TYPE_CD , A.SSVC_GROUP_NM , A.SSVC_GROUP_CD , A.SSVC_OBJ_NM , A.SSVC_OBJ_CD , A.SIP_CREATE_TYPE_NM , A.SIP_VERSION_TYPE_NM , A.NBLOCK_SIZE , NVL(A.NALL_CNT,0) AS NALL_CNT , NVL(A.NALLOC_CNT,0) AS NALLOC_CNT , NVL(A.NASSIGN_CNT,0) AS NASSIGN_CNT , SUM(NVL(A.NALL_CNT, 0)) OVER(PARTITION BY A.SSVC_LINE_TYPE_CD,A.SSVC_GROUP_CD,A.SSVC_OBJ_CD,A.SIP_CREATE_TYPE_CD,A.SIP_VERSION_TYPE_CD) AS NALL_CNT_ALL , SUM(NVL(A.NALLOC_CNT, 0)) OVER(PARTITION BY A.SSVC_LINE_TYPE_CD,A.SSVC_GROUP_CD,A.SSVC_OBJ_CD,A.SIP_CREATE_TYPE_CD,A.SIP_VERSION_TYPE_CD) AS NALLOC_CNT_ALL , SUM(NVL(A.NASSIGN_CNT, 0)) OVER(PARTITION BY A.SSVC_LINE_TYPE_CD,A.SSVC_GROUP_CD,A.SSVC_OBJ_CD,A.SIP_CREATE_TYPE_CD,A.SIP_VERSION_TYPE_CD) AS NASSIGN_CNT_ALL FROM ( SELECT A.SSVC_LINE_TYPE_CD, A.SSVC_LINE_TYPE_NM, A.NLVL_MST_SEQ , C.SLVL_CD AS SSVC_GROUP_CD, C.SLVL_NM AS SSVC_GROUP_NM, D.SLVL_CD AS SSVC_OBJ_CD, D.SLVL_NM AS SSVC_OBJ_NM, E.SIP_CREATE_TYPE_CD , E.SIP_CREATE_TYPE_NM , F.SIP_VERSION_TYPE_CD , F.SIP_VERSION_TYPE_NM , B.NLVL_MST_SEQ , B.NBLOCK_SIZE , B.NALL_CNT , B.NASSIGN_CNT , B.NALLOC_CNT FROM ( SELECT A.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , C.SSVC_GROUP_CD , C.SSVC_OBJ_CD , C.NLVL_MST_SEQ FROM MST.TB_SVC_LINE_TYPE_CD A , MST.TB_LVL_MST C WHERE 1=1 AND C.SSVC_LINE_TYPE_CD(+) = A.SSVC_LINE_TYPE_CD ) A , ( SELECT SHIST_DT , SSVC_LINE_TYPE_CD , NLVL_MST_SEQ , SIP_CREATE_TYPE_CD , SIP_VERSION_TYPE_CD , NBLOCK_SIZE , NALL_CNT , NASSIGN_CNT , NALLOC_CNT FROM MST.TB_ORG_BLOCK_STATS_MST WHERE 1=1 AND SHIST_DT = #{searchBgnDe, jdbcType=VARCHAR}
AND SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND SIP_VERSION_TYPE_CD = #{sipVersionTypeCd, jdbcType=CHAR}
AND SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR}
) B , MST.TB_LVL_CD C , MST.TB_LVL_CD D , MST.TB_IP_CREATE_TYPE_CD E , MST.TB_IP_VERSION_TYPE_CD F WHERE 1=1 AND B.SSVC_LINE_TYPE_CD(+) = A.SSVC_LINE_TYPE_CD AND B.NLVL_MST_SEQ(+) = A.NLVL_MST_SEQ AND C.SLVL_CD(+) = A.SSVC_GROUP_CD AND D.SLVL_CD(+) = A.SSVC_OBJ_CD AND E.SIP_CREATE_TYPE_CD(+) = NVL(B.SIP_CREATE_TYPE_CD, #{sipCreateTypeCd, jdbcType=CHAR}) AND F.SIP_VERSION_TYPE_CD(+) = NVL(B.SIP_VERSION_TYPE_CD, #{sipVersionTypeCd, jdbcType=CHAR}) ORDER BY A.SSVC_LINE_TYPE_CD , A.SSVC_GROUP_CD , A.SSVC_OBJ_CD ) A ) SELECT A.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD , A.SSVC_OBJ_NM , A.SIP_CREATE_TYPE_NM , A.SIP_VERSION_TYPE_NM , A.NALL_CNT_ALL , A.NALLOC_CNT_ALL , A.NASSIGN_CNT_ALL
, NVL(TO_CHAR(MIN(CASE A.NBLOCK_SIZE WHEN #{item.code} THEN A.NALL_CNT END)),'0') AS NALL_CNT_${item.code} , NVL(TO_CHAR(MIN(CASE A.NBLOCK_SIZE WHEN #{item.code} THEN A.NALLOC_CNT END)), '0') AS NALLOC_CNT_${item.code} , NVL(TO_CHAR(MIN(CASE A.NBLOCK_SIZE WHEN #{item.code} THEN A.NASSIGN_CNT END)), '0') AS NASSIGN_CNT_${item.code}
FROM ( SELECT T1.SSVC_LINE_TYPE_NM , T1.SSVC_LINE_TYPE_CD , T1.SSVC_GROUP_NM , T1.SSVC_GROUP_CD , T1.SSVC_OBJ_NM , T1.SSVC_OBJ_CD , T1.SIP_CREATE_TYPE_NM , T1.SIP_VERSION_TYPE_NM , T1.NBLOCK_SIZE , NVL(T1.NALL_CNT,0) AS NALL_CNT , NVL(T1.NALLOC_CNT,0) AS NALLOC_CNT , NVL(T1.NASSIGN_CNT,0) AS NASSIGN_CNT , T1.NALL_CNT_ALL , T1.NALLOC_CNT_ALL , T1.NASSIGN_CNT_ALL FROM T1 ) A WHERE 1=1
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
GROUP BY A.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD , A.SSVC_OBJ_NM , A.SIP_CREATE_TYPE_NM , A.SIP_VERSION_TYPE_NM , A.NALL_CNT_ALL , A.NALLOC_CNT_ALL , A.NASSIGN_CNT_ALL ORDER BY A.SSVC_LINE_TYPE_CD , A.SSVC_GROUP_CD , A.SSVC_OBJ_CD
